1	---
2	import '../styles/global.css';
3	import { config } from '../data/hub.config';
4	
5	interface Props {
6	  title: string;
7	  description?: string;
8	  image?: string;
9	}
10	
11	const { 
12	  title, 
13	  description = config.tagline,
14	  image = '/og-default.svg'
15	} = Astro.props;
16	
17	const canonicalURL = new URL(Astro.url.pathname, Astro.site || config.domains.hub);
18	---
19	
20	<!doctype html>
21	<html lang="en">
22	  <head>
23	    <meta charset="UTF-8" />
24	    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
25	    <title>{title}</title>
26	    
27	    <!-- Primary Meta Tags -->
28	    <meta name="title" content={title} />
29	    <meta name="description" content={description} />
30	    <link rel="canonical" href={canonicalURL} />
31	
32	    <!-- Open Graph / Facebook -->
33	    <meta property="og:type" content="website" />
34	    <meta property="og:url" content={canonicalURL} />
35	    <meta property="og:title" content={title} />
36	    <meta property="og:description" content={description} />
37	    <meta property="og:image" content={new URL(image, Astro.site)} />
38	
39	    <!-- Twitter -->
40	    <meta name="twitter:card" content="summary_large_image" />
41	    <meta name="twitter:url" content={canonicalURL} />
42	    <meta name="twitter:title" content={title} />
43	    <meta name="twitter:description" content={description} />
44	    <meta name="twitter:image" content={new URL(image, Astro.site)} />
45	
46	    <link rel="preconnect" href="https://fonts.googleapis.com" />
47	    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin />
48	    <link
49	      href="https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;1,400&family=Inter:wght@300;400;500&display=swap"
50	      rel="stylesheet"
51	    />
52	  </head>
53	  <body class="min-h-screen flex flex-col bg-ocean-900 text-white/60">
54	    <nav class="fixed top-0 left-0 right-0 z-50 bg-ocean-900/60 backdrop-blur-xl border-b border-white/[0.04]">
55	      <div class="max-w-6xl mx-auto px-6 md:px-10 py-4 flex items-center justify-between">
56	        <a href="/" class="font-heading text-base font-light text-white/70 hover:text-white transition-colors tracking-wide">
57	          {config.name}
58	        </a>
59	        <!-- Desktop nav -->
60	        <div class="hidden md:flex gap-8">
61	          <a href="/water/" class="text-[11px] font-medium tracking-[0.15em] uppercase text-ocean-400 hover:text-white transition-colors">Water</a>
62	          <a href="/business/" class="text-[11px] font-medium tracking-[0.15em] uppercase text-ocean-400 hover:text-white transition-colors">Business</a>
63	          <a href="/water/explore" class="text-[11px] font-medium tracking-[0.15em] uppercase text-ocean-400 hover:text-white transition-colors">Explore</a>
64	          <a href="/water/quiz" class="text-[11px] font-medium tracking-[0.15em] uppercase text-ocean-400 hover:text-white transition-colors">Quiz</a>
65	        </div>
66	        <!-- Mobile hamburger -->
67	        <button id="nav-toggle" class="md:hidden p-2 -mr-2 text-ocean-400" aria-label="Menu">
68	          <svg id="nav-icon-open" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"><line x1="4" y1="7" x2="20" y2="7"/><line x1="4" y1="12" x2="20" y2="12"/><line x1="4" y1="17" x2="20" y2="17"/></svg>
69	          <svg id="nav-icon-close" class="hidden" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"><line x1="6" y1="6" x2="18" y2="18"/><line x1="6" y1="18" x2="18" y2="6"/></svg>
70	        </button>
71	      </div>
72	      <!-- Mobile menu panel -->
73	      <div id="nav-menu" class="hidden md:hidden border-t border-white/[0.04] bg-ocean-900/95 backdrop-blur-xl">
74	        <div class="px-6 py-6 flex flex-col gap-5">
75	          <a href="/water/" class="text-[13px] font-medium tracking-[0.12em] uppercase text-ocean-400 active:text-white py-1">Water</a>
76	          <a href="/business/" class="text-[13px] font-medium tracking-[0.12em] uppercase text-ocean-400 active:text-white py-1">Business</a>
77	          <a href="/water/explore" class="text-[13px] font-medium tracking-[0.12em] uppercase text-ocean-400 active:text-white py-1">Explore</a>
78	          <a href="/water/quiz" class="text-[13px] font-medium tracking-[0.12em] uppercase text-ocean-400 active:text-white py-1">Quiz</a>
79	        </div>
80	      </div>
81	    </nav>
82	    <script>
83	      const toggle = document.getElementById('nav-toggle');
84	      const menu = document.getElementById('nav-menu');
85	      const iconOpen = document.getElementById('nav-icon-open');
86	      const iconClose = document.getElementById('nav-icon-close');
87	      toggle?.addEventListener('click', () => {
88	        const open = menu?.classList.toggle('hidden') === false;
89	        iconOpen?.classList.toggle('hidden', open);
90	        iconClose?.classList.toggle('hidden', !open);
91	      });
92	      // Close on link tap
93	      menu?.querySelectorAll('a').forEach(a => a.addEventListener('click', () => {
94	        menu.classList.add('hidden');
95	        iconOpen?.classList.remove('hidden');
96	        iconClose?.classList.add('hidden');
97	      }));
98	    </script>
99	
100	    <main class="flex-1 pt-[56px]">
101	      <slot />
102	    </main>
103	
104	    <footer class="border-t border-white/[0.03] bg-ocean-900">
105	      <div class="max-w-6xl mx-auto px-6 py-10 text-center">
106	        <p class="text-[12px] text-white/20">&copy; {new Date().getFullYear()} {config.name}</p>
107	        <p class="mt-1 text-[11px] text-white/10 tracking-[0.1em]">{config.domains.hub}</p>
108	      </div>
109	    </footer>
110	
111	    <script>
112	      // Citation tooltips — lazy-load data on first hover
113	      let citations = null;
114	      let tooltip = null;
115	
116	      function createTooltip() {
117	        const el = document.createElement('div');
118	        el.id = 'cite-tooltip';
119	        el.style.cssText = `
120	          position:fixed; z-index:9999; pointer-events:none; opacity:0;
121	          transition:opacity 0.15s; max-width:320px; padding:14px 16px;
122	          background:#0c2e33; border:1px solid rgba(17,154,158,0.25);
123	          border-radius:10px; box-shadow:0 12px 40px rgba(0,0,0,0.5);
124	          font-family:Inter,system-ui,sans-serif;
125	        `;
126	        document.body.appendChild(el);
127	        return el;
128	      }
129	
130	      async function loadCitations() {
131	        if (citations) return citations;
132	        try {
133	          const res = await fetch('/citations.json');
134	          citations = await res.json();
135	        } catch { citations = []; }
136	        return citations;
137	      }
138	
139	      function findCitation(id) {
140	        return citations?.find(c => c.id === id);
141	      }
142	
143	      function renderTooltip(cite, isBio) {
144	        return `
145	          <div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:0.12em;color:#7dd3d7;margin-bottom:6px;">
146	            ${isBio ? 'Peer-Reviewed Research' : 'Sacred / Philosophical Source'}
147	          </div>
148	          <div style="font-size:13px;font-weight:500;color:#fff;line-height:1.4;margin-bottom:6px;">
149	            ${cite.source}
150	          </div>
151	          <div style="font-size:12px;color:rgba(255,255,255,0.5);line-height:1.5;font-style:italic;">
152	            "${cite.detail}"
153	          </div>
154	          ${cite.context.startsWith('http') ? `<div style="font-size:10px;color:#3dbfc4;margin-top:8px;font-family:monospace;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${cite.context}</div>` : ''}
155	        `;
156	      }
157	
158	      function positionTooltip(sup) {
159	        if (!tooltip) return;
160	        const rect = sup.getBoundingClientRect();
161	        const maxW = Math.min(320, window.innerWidth - 16);
162	        tooltip.style.maxWidth = maxW + 'px';
163	        let left = rect.left + rect.width / 2 - maxW / 2;
164	        left = Math.max(8, Math.min(left, window.innerWidth - maxW - 8));
165	        tooltip.style.left = left + 'px';
166	        tooltip.style.top = (rect.top - tooltip.offsetHeight - 8) + 'px';
167	        if (rect.top - tooltip.offsetHeight - 8 < 8) {
168	          tooltip.style.top = (rect.bottom + 8) + 'px';
169	        }
170	        tooltip.style.opacity = '1';
171	      }
172	
173	      function hideTooltip() {
174	        if (tooltip) tooltip.style.opacity = '0';
175	      }
176	
177	      let activeSup = null;
178	
179	      async function showForSup(sup) {
180	        const id = sup.textContent.trim();
181	        if (!/^[SB]-\d+$/.test(id)) return;
182	        await loadCitations();
183	        const cite = findCitation(id);
184	        if (!cite) return;
185	        if (!tooltip) tooltip = createTooltip();
186	        tooltip.innerHTML = renderTooltip(cite, id.startsWith('B-'));
187	        activeSup = sup;
188	        requestAnimationFrame(() => positionTooltip(sup));
189	      }
190	
191	      // Desktop: hover
192	      document.addEventListener('mouseover', (e) => {
193	        const sup = e.target.closest('sup');
194	        if (sup) showForSup(sup);
195	      });
196	      document.addEventListener('mouseout', (e) => {
197	        if (e.target.closest('sup')) hideTooltip();
198	      });
199	
200	      // Mobile: tap to toggle
201	      document.addEventListener('click', (e) => {
202	        const sup = e.target.closest('sup');
203	        if (sup) {
204	          e.preventDefault();
205	          if (activeSup === sup && tooltip?.style.opacity === '1') {
206	            hideTooltip();
207	            activeSup = null;
208	          } else {
209	            showForSup(sup);
210	          }
211	        } else if (tooltip?.style.opacity === '1') {
212	          hideTooltip();
213	          activeSup = null;
214	        }
215	      });
216	    </script>
217	  </body>
218	</html>
219

