        <EmailGate preview={`The full ${title} framework — what it addresses, where to start, and how it connects to the spiral.`}>
          <div class="branch-content text-[16px] leading-[1.9]">
            <Content />
          </div>
          {citationIds.length > 0 && (
            <ResearchAccordion ids={citationIds} />
