import { getCollection } from 'astro:content';
import Base from '../../layouts/Base.astro';
import CTAButton from '../../components/CTAButton.astro';
import ComingSoon from '../../components/ComingSoon.astro';
import ResearchAccordion from '../../components/ResearchAccordion.astro';
import VerticalSpine from '../../components/VerticalSpine.astro';
import EmailGate from '../../components/EmailGate.astro';
import { config } from '../../data/hub.config';

export async function getStaticPaths() {
  const branches = await getCollection('branches');
  return branches.map((branch) => ({
    params: { slug: branch.id.replace(/\.md$/, '') },
    props: { branch },
  }));
}

const { branch } = Astro.props;
const { Content } = await branch.render();
const { title, emoji, hook, status, tone } = branch.data;
const ctaLabel = tone === 'soft' ? 'Explore gently' : 'Start with your water';

const branchConfig = config.branches.find(b => b.slug === branch.id.replace(/\.md$/, ''));
const citationIds = branchConfig?.citationIds || [];
const branchGhlUrl = branchConfig?.ghlUrl || config.ghl.productUrl;
