  <!-- Deep content — GATED (Layer 2) -->
  <div class="divider-line"></div>
  <section class="py-16 px-6 bg-ocean-900">
    <div class="max-w-[640px] mx-auto">
      {status === 'placeholder' ? (
        <ComingSoon title={title} emoji={emoji} />
      ) : (
        <EmailGate preview={`Research-backed deep dive into ${title.toLowerCase()} — what it means, where water fits, and what the science shows.`}>
          <div class="branch-content text-[16px] leading-[1.9]">
            <Content />
          </div>
          <ResearchAccordion ids={citationIds} />
