  </section>

  <!-- CTA — FREE (visible to drive conversion) -->
  <section class="py-20 px-6 glow-bg text-center border-t border-ocean-500/10">
    <div class="relative flex flex-col sm:flex-row gap-4 justify-center items-center">
      <CTAButton href={branchGhlUrl} label={ctaLabel} />
      <CTAButton href="/water/explore" label="Explore other branches" variant="secondary" />
