---
import '../styles/global.css';
import { config } from '../data/hub.config';

interface Props {
  title: string;
  description?: string;
  image?: string;
}

const { 
  title, 
  description = config.tagline,
  image = '/og-default.svg'
} = Astro.props;

const canonicalURL = new URL(Astro.url.pathname, Astro.site || config.domains.hub);
---

<!doctype html>
<html lang="en">
  <head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
    <title>{title}</title>

    <!-- Primary Meta Tags -->
    <meta name="title" content={title} />
    <meta name="description" content={description} />
    <link rel="canonical" href={canonicalURL} />

    <!-- Open Graph / Facebook -->
    <meta property="og:type" content="website" />
    <meta property="og:url" content={canonicalURL} />
    <meta property="og:title" content={title} />
    <meta property="og:description" content={description} />
    <meta property="og:image" content={new URL(image, Astro.site)} />

    <!-- Twitter -->
    <meta name="twitter:card" content="summary_large_image" />
    <meta name="twitter:url" content={canonicalURL} />
    <meta name="twitter:title" content={title} />
    <meta name="twitter:description" content={description} />
    <meta name="twitter:image" content={new URL(image, Astro.site)} />

    <link rel="preconnect" href="https://fonts.googleapis.com" />
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin />
    <link
      href="https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;1,400&family=Inter:wght@300;400;500&display=swap"
      rel="stylesheet"
    />
  </head>
  <body class="min-h-screen flex flex-col bg-ocean-900 text-white/60">
    <nav class="fixed top-0 left-0 right-0 z-50 bg-ocean-900/60 backdrop-blur-xl border-b border-white/[0.04]">
      <div class="max-w-6xl mx-auto px-6 md:px-10 py-4 flex items-center justify-between">
        <a href="/" class="font-heading text-base font-light text-white/70 hover:text-white transition-colors tracking-wide">
          {config.name}
        </a>
        <!-- Desktop nav -->
        <div class="hidden md:flex gap-8">
          <a href="/water/" class="text-[11px] font-medium tracking-[0.15em] uppercase text-ocean-400 hover:text-white transition-colors">Water</a>
          <a href="/business/" class="text-[11px] font-medium tracking-[0.15em] uppercase text-ocean-400 hover:text-white transition-colors">Business</a>
          <a href="/water/explore" class="text-[11px] font-medium tracking-[0.15em] uppercase text-ocean-400 hover:text-white transition-colors">Explore</a>
          <a href="/water/quiz" class="text-[11px] font-medium tracking-[0.15em] uppercase text-ocean-400 hover:text-white transition-colors">Quiz</a>
        </div>
        <!-- Mobile hamburger -->
        <button id="nav-toggle" class="md:hidden p-2 -mr-2 text-ocean-400" aria-label="Menu">
          <svg id="nav-icon-open" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"><line x1="4" y1="7" x2="20" y2="7"/><line x1="4" y1="12" x2="20" y2="12"/><line x1="4" y1="17" x2="20" y2="17"/></svg>
          <svg id="nav-icon-close" class="hidden" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"><line x1="6" y1="6" x2="18" y2="18"/><line x1="6" y1="18" x2="18" y2="6"/></svg>
        </button>
      </div>
      <!-- Mobile menu panel -->
      <div id="nav-menu" class="hidden md:hidden border-t border-white/[0.04] bg-ocean-900/95 backdrop-blur-xl">
        <div class="px-6 py-6 flex flex-col gap-5">
          <a href="/water/" class="text-[13px] font-medium tracking-[0.12em] uppercase text-ocean-400 active:text-white py-1">Water</a>
