import '../styles/global.css';
import { config } from '../data/hub.config';
import Breadcrumbs from '../components/Breadcrumbs.astro';

interface Props {
  title: string;
  description?: string;
  image?: string;
}

const {
  title,
  description = config.tagline,
  image = '/og-default.svg'
} = Astro.props;

const canonicalURL = new URL(Astro.url.pathname, Astro.site || config.domains.hub);

// --- Active page detection ---
const currentPath = Astro.url.pathname;
const isWaterSection = currentPath.startsWith('/water');
const isHome = currentPath === '/';

function navClass(href: string): string {
  const active = href === '/'
    ? currentPath === '/'
    : currentPath === href || currentPath === href.replace(/\/$/, '') || currentPath.startsWith(href);
  return active
    ? 'text-white'
    : 'text-ocean-400 hover:text-white';
}

function mobileNavClass(href: string): string {
  const active = href === '/'
    ? currentPath === '/'
    : currentPath === href || currentPath === href.replace(/\/$/, '') || currentPath.startsWith(href);
  return active
    ? 'text-white border-l-2 border-ocean-400 pl-3'
    : 'text-ocean-400 active:text-white';
}

function subNavClass(href: string): string {
  const normalized = currentPath.replace(/\/$/, '');
  const hrefNormalized = href.replace(/\/$/, '');
  return normalized === hrefNormalized
    ? 'text-white'
    : 'text-ocean-400/60 hover:text-white/70';
}

// --- Breadcrumb data ---
type BreadcrumbItem = { label: string; href?: string };
const breadcrumbs: BreadcrumbItem[] = [];

if (!isHome) {
  breadcrumbs.push({ label: 'Home', href: '/' });

  if (isWaterSection) {
    const subPath = currentPath.replace('/water/', '').replace(/\/$/, '');
    if (!subPath || subPath === 'water') {
      breadcrumbs.push({ label: 'Water' });
    } else if (subPath === 'quiz') {
      breadcrumbs.push({ label: 'Water', href: '/water/' });
      breadcrumbs.push({ label: 'Quiz' });
    } else if (subPath === 'explore') {
      breadcrumbs.push({ label: 'Water', href: '/water/' });
      breadcrumbs.push({ label: 'Branches' });
    } else {
      const branchName = config.branches.find(b => b.slug === subPath)?.name;
      breadcrumbs.push({ label: 'Water', href: '/water/' });
      breadcrumbs.push({ label: branchName || subPath });
    }
  } else if (currentPath.startsWith('/pillars/')) {
    const slug = currentPath.replace('/pillars/', '').replace(/\/$/, '');
    const pillar = config.pillars.find(p => p.slug === slug);
    breadcrumbs.push({ label: pillar?.name || slug });
  } else if (currentPath.startsWith('/business')) {
    breadcrumbs.push({ label: 'Business' });
  } else if (currentPath.startsWith('/research')) {
    breadcrumbs.push({ label: 'Research' });
  }
}
