<!doctype html>
<html lang="en">
  <head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
    <title>{title}</title>

    <!-- Primary Meta Tags -->
    <meta name="title" content={title} />
    <meta name="description" content={description} />
    <link rel="canonical" href={canonicalURL} />

    <!-- Open Graph / Facebook -->
    <meta property="og:type" content="website" />
    <meta property="og:url" content={canonicalURL} />
    <meta property="og:title" content={title} />
    <meta property="og:description" content={description} />
    <meta property="og:image" content={new URL(image, Astro.site)} />

    <!-- Twitter -->
    <meta name="twitter:card" content="summary_large_image" />
    <meta name="twitter:url" content={canonicalURL} />
    <meta name="twitter:title" content={title} />
    <meta name="twitter:description" content={description} />
    <meta name="twitter:image" content={new URL(image, Astro.site)} />

    <link rel="preconnect" href="https://fonts.googleapis.com" />
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin />
    <link
      href="https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;1,400&family=Inter:wght@300;400;500&display=swap"
      rel="stylesheet"
    />
  </head>
  <body class="min-h-screen flex flex-col bg-ocean-900 text-white/60">
    <nav class="fixed top-0 left-0 right-0 z-50 bg-ocean-900/60 backdrop-blur-xl border-b border-white/[0.04]">
      <div class="max-w-6xl mx-auto px-6 md:px-10 py-4 flex items-center justify-between">
        <a href="/" class="font-heading text-base font-light text-white/70 hover:text-white transition-colors tracking-wide">
          {config.name}
        </a>
        <!-- Desktop nav -->
        <div class="hidden md:flex gap-8">
          <a href="/water/" class="text-[11px] font-medium tracking-[0.15em] uppercase text-ocean-400 hover:text-white transition-colors">Water</a>
          <a href="/business/" class="text-[11px] font-medium tracking-[0.15em] uppercase text-ocean-400 hover:text-white transition-colors">Business</a>
          <a href="/water/explore" class="text-[11px] font-medium tracking-[0.15em] uppercase text-ocean-400 hover:text-white transition-colors">Explore</a>
          <a href="/water/quiz" class="text-[11px] font-medium tracking-[0.15em] uppercase text-ocean-400 hover:text-white transition-colors">Quiz</a>
        </div>
        <!-- Mobile hamburger -->
        <button id="nav-toggle" class="md:hidden p-2 -mr-2 text-ocean-400" aria-label="Menu">
          <svg id="nav-icon-open" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"><line x1="4" y1="7" x2="20" y2="7"/><line x1="4" y1="12" x2="20" y2="12"/><line x1="4" y1="17" x2="20" y2="17"/></svg>
          <svg id="nav-icon-close" class="hidden" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"><line x1="6" y1="6" x2="18" y2="18"/><line x1="6" y1="18" x2="18" y2="6"/></svg>
        </button>
      </div>
      <!-- Mobile menu panel -->
      <div id="nav-menu" class="hidden md:hidden border-t border-white/[0.04] bg-ocean-900/95 backdrop-blur-xl">
        <div class="px-6 py-6 flex flex-col gap-5">
          <a href="/water/" class="text-[13px] font-medium tracking-[0.12em] uppercase text-ocean-400 active:text-white py-1">Water</a>
          <a href="/business/" class="text-[13px] font-medium tracking-[0.12em] uppercase text-ocean-400 active:text-white py-1">Business</a>
          <a href="/water/explore" class="text-[13px] font-medium tracking-[0.12em] uppercase text-ocean-400 active:text-white py-1">Explore</a>
          <a href="/water/quiz" class="text-[13px] font-medium tracking-[0.12em] uppercase text-ocean-400 active:text-white py-1">Quiz</a>
        </div>
      </div>
    </nav>
    <script>
      const toggle = document.getElementById('nav-toggle');
      const menu = document.getElementById('nav-menu');
      const iconOpen = document.getElementById('nav-icon-open');
      const iconClose = document.getElementById('nav-icon-close');
      toggle?.addEventListener('click', () => {
        const open = menu?.classList.toggle('hidden') === false;
        iconOpen?.classList.toggle('hidden', open);
        iconClose?.classList.toggle('hidden', !open);
      });
      // Close on link tap
      menu?.querySelectorAll('a').forEach(a => a.addEventListener('click', () => {
        menu.classList.add('hidden');
        iconOpen?.classList.remove('hidden');
        iconClose?.classList.add('hidden');
      }));
    </script>

    <main class="flex-1 pt-[56px]">
      <slot />
    </main>

    <footer class="border-t border-white/[0.03] bg-ocean-900">
      <div class="max-w-6xl mx-auto px-6 py-10 text-center">
        <p class="text-[12px] text-white/20">&copy; {new Date().getFullYear()} {config.name}</p>
        <p class="mt-1 text-[11px] text-white/10 tracking-[0.1em]">{config.domains.hub}</p>
      </div>
    </footer>

    <script>
      // Citation tooltips — lazy-load data on first hover
      let citations = null;
      let tooltip = null;

      function createTooltip() {
        const el = document.createElement('div');
        el.id = 'cite-tooltip';
        el.style.cssText = `
          position:fixed; z-index:9999; pointer-events:none; opacity:0;
          transition:opacity 0.15s; max-width:320px; padding:14px 16px;
          background:#0c2e33; border:1px solid rgba(17,154,158,0.25);
          border-radius:10px; box-shadow:0 12px 40px rgba(0,0,0,0.5);
          font-family:Inter,system-ui,sans-serif;
        `;
        document.body.appendChild(el);
        return el;
      }

      async function loadCitations() {
        if (citations) return citations;
        try {
          const res = await fetch('/citations.json');
          citations = await res.json();
        } catch { citations = []; }
        return citations;
      }

      function findCitation(id) {
        return citations?.find(c => c.id === id);
      }

      function renderTooltip(cite, isBio) {
        return `
          <div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:0.12em;color:#7dd3d7;margin-bottom:6px;">
            ${isBio ? 'Peer-Reviewed Research' : 'Sacred / Philosophical Source'}
          </div>
          <div style="font-size:13px;font-weight:500;color:#fff;line-height:1.4;margin-bottom:6px;">
            ${cite.source}
          </div>
          <div style="font-size:12px;color:rgba(255,255,255,0.5);line-height:1.5;font-style:italic;">
            "${cite.detail}"
          </div>
          ${cite.context.startsWith('http') ? `<div style="font-size:10px;color:#3dbfc4;margin-top:8px;font-family:monospace;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${cite.context}</div>` : ''}
        `;
      }

      function positionTooltip(sup) {
        if (!tooltip) return;
        const rect = sup.getBoundingClientRect();
        const maxW = Math.min(320, window.innerWidth - 16);
        tooltip.style.maxWidth = maxW + 'px';
        let left = rect.left + rect.width / 2 - maxW / 2;
        left = Math.max(8, Math.min(left, window.innerWidth - maxW - 8));
        tooltip.style.left = left + 'px';
        tooltip.style.top = (rect.top - tooltip.offsetHeight - 8) + 'px';
        if (rect.top - tooltip.offsetHeight - 8 < 8) {
          tooltip.style.top = (rect.bottom + 8) + 'px';
        }
        tooltip.style.opacity = '1';
      }

      function hideTooltip() {
        if (tooltip) tooltip.style.opacity = '0';
      }

      let activeSup = null;

      async function showForSup(sup) {
        const id = sup.textContent.trim();
        if (!/^[SB]-\d+$/.test(id)) return;
        await loadCitations();
        const cite = findCitation(id);
        if (!cite) return;
        if (!tooltip) tooltip = createTooltip();
        tooltip.innerHTML = renderTooltip(cite, id.startsWith('B-'));
        activeSup = sup;
        requestAnimationFrame(() => positionTooltip(sup));
      }

      // Desktop: hover
      document.addEventListener('mouseover', (e) => {
        const sup = e.target.closest('sup');
        if (sup) showForSup(sup);
      });
      document.addEventListener('mouseout', (e) => {
        if (e.target.closest('sup')) hideTooltip();
      });

      // Mobile: tap to toggle
      document.addEventListener('click', (e) => {
        const sup = e.target.closest('sup');
        if (sup) {
          e.preventDefault();
          if (activeSup === sup && tooltip?.style.opacity === '1') {
            hideTooltip();
            activeSup = null;
          } else {
            showForSup(sup);
          }
        } else if (tooltip?.style.opacity === '1') {
          hideTooltip();
          activeSup = null;
        }
      });
    </script>
  </body>
</html>

---
import { getCollection } from 'astro:content';
import Base from '../../layouts/Base.astro';
import CTAButton from '../../components/CTAButton.astro';
import ComingSoon from '../../components/ComingSoon.astro';
import ResearchAccordion from '../../components/ResearchAccordion.astro';
import VerticalSpine from '../../components/VerticalSpine.astro';
import EmailGate from '../../components/EmailGate.astro';
import { config } from '../../data/hub.config';

export async function getStaticPaths() {
  const branches = await getCollection('branches');
  return branches.map((branch) => ({
    params: { slug: branch.id.replace(/\.md$/, '') },
    props: { branch },
  }));
}

const { branch } = Astro.props;
const { Content } = await branch.render();
const { title, emoji, hook, status, tone } = branch.data;
const ctaLabel = tone === 'soft' ? 'Explore gently' : 'Start with your water';

const branchConfig = config.branches.find(b => b.slug === branch.id.replace(/\.md$/, ''));
const citationIds = branchConfig?.citationIds || [];
const branchGhlUrl = branchConfig?.ghlUrl || config.ghl.productUrl;
---

<Base title={`${title} — Water`}>
  <VerticalSpine />
  <!-- Branch header — FREE (Layer 1) -->
  <section class="relative min-h-[60vh] flex flex-col items-center justify-center text-center px-6 py-24 glow-bg overflow-hidden">
    <div class="relative text-6xl mb-6">{emoji}</div>
    <h1 class="relative font-heading text-[clamp(40px,5vw,64px)] font-light text-white leading-[1.1] mb-6" style="text-shadow: 0 0 50px rgba(17,154,158,0.12);">
      {title}
    </h1>
    <p class="relative font-heading italic text-white/45 text-[clamp(18px,2.5vw,24px)] leading-relaxed max-w-2xl">
      {hook}
    </p>
  </section>

  <!-- Deep content — GATED (Layer 2) -->
  <div class="divider-line"></div>
  <section class="py-16 px-6 bg-ocean-900">
    <div class="max-w-[640px] mx-auto">
      {status === 'placeholder' ? (
        <ComingSoon title={title} emoji={emoji} />
      ) : (
        <EmailGate preview={`Research-backed deep dive into ${title.toLowerCase()} — what it means, where water fits, and what the science shows.`}>
          <div class="branch-content text-[16px] leading-[1.9]">
            <Content />
          </div>
          <ResearchAccordion ids={citationIds} />
        </EmailGate>
      )}
    </div>
  </section>

  <!-- CTA — FREE (visible to drive conversion) -->
  <section class="py-20 px-6 glow-bg text-center border-t border-ocean-500/10">
    <div class="relative flex flex-col sm:flex-row gap-4 justify-center items-center">
      <CTAButton href={branchGhlUrl} label={ctaLabel} />
      <CTAButton href="/water/explore" label="Explore other branches" variant="secondary" />
    </div>
  </section>
</Base>
